import java.io.UnsupportedEncodingException;
import java.net.URLEncoder;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Encode the user input to prevent XSS
        String encodedInput = encodeForHtml(userInput);

        // Output the encoded user input
        System.out.println("User input: " + encodedInput);
    }

    public static String encodeForHtml(String input) {
        return input
                .replace("&", "&amp;")
                .replace("\"", "&quot;")
                .replace("<", "&lt;")
                .replace(">", "&gt;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
